package com.xwc.open.easybatis;import com.xwc.open.easybatis.enums.IdType;import lombok.Data;import org.apache.ibatis.session.Configuration;import org.springframework.core.env.Environment;@Datapublic class EasyBatisEnvironment {    private Configuration configuration;    /**     * 如果 tablePrefix 有值就默认开启根据类名映射标明     */    private String tablePrefix;    private IdType idType;    public EasyBatisEnvironment(Environment environment, Configuration configuration) {        this.configuration = configuration;        initEasybatisEnvironment(environment);    }    public EasyBatisEnvironment(Configuration configuration) {        this.configuration = configuration;    }    public boolean isUseActualParamName() {        return configuration.isUseActualParamName();    }    public boolean isMapUnderscoreToCamelCase() {        return configuration.isMapUnderscoreToCamelCase();    }    public IdType useGlobalPrimaKeyType() {        return idType;    }    private void initEasybatisEnvironment(Environment environment) {        if (tablePrefix == null) {            this.tablePrefix = environment.getProperty("${easybatis.table.prefix}");        }        if (idType == null) {            String property = environment.getProperty("${easybatis.table.id}");            if (property == null) {                this.idType = IdType.AUTO;            } else {                try {                    IdType.valueOf(property);                } catch (Exception e) {                    this.idType = IdType.AUTO;                }            }        }    }}